const express = require('express');
const jwt = require('express-jwt');

const app = express();

// Define the authentication middleware
const authenticate = jwt({ secret: 'your-secret-key' });

// Define the route parameter validation middleware
const validateRouteParams = (req, res, next) => {
  if (!req.params.id) {
    return res.status(400).send({ error: 'Missing route parameter' });
  }
  next();
};

// Define the route handler
const get_user = (req, res) => {
  res.send({ authenticated: true, params: { id: req.params.id } });
};

// Define the routes
app.get('/users/:id', authenticate, validateRouteParams, get_user);

// Export the routes
module.exports = app;
